// 分块大小设为TILE=32或64
for (ii = 0; ii < _PB_NI; ii += TILE)
  for (jj = 0; jj < _PB_NJ; jj += TILE)
    for (kk = 0; kk < _PB_NK; kk += TILE)
      for (i = ii; i < min(ii+TILE, _PB_NI); i++)
        for (j = jj; j < min(jj+TILE, _PB_NJ); j++) {
          DATA_TYPE sum = E[i][j];
          for (k = kk; k < min(kk+TILE, _PB_NK); k++)
            sum += A[i][k] * B[k][j];
          E[i][j] = sum;
        }

// 将k循环提到外层，提高数据局部性
for (k = 0; k < _PB_NM; k++)
  for (i = 0; i < _PB_NJ; i++)
    for (j = 0; j < _PB_NL; j++)
      F[i][j] += C[i][k] * D[k][j];
// 同时添加预取指令
#pragma vector aligned
#pragma prefetch C[i][k:4]
#pragma prefetch D[k][j:4]

// 使用编译器指令启用向量化
#pragma omp simd reduction(+:sum)
// 手动展开内层循环4次
for (k = 0; k < _PB_NK; k += 4) {
  sum += A[i][k] * B[k][j];
  sum += A[i][k+1] * B[k+1][j];
  sum += A[i][k+2] * B[k+2][j];
  sum += A[i][k+3] * B[k+3][j];
}
// 处理剩余元素

// 将三个矩阵乘法融合，避免中间矩阵E和F的存储
for (i = 0; i < _PB_NI; i++)
  for (j = 0; j < _PB_NL; j++) {
    DATA_TYPE sum = 0.0;
    for (k1 = 0; k1 < _PB_NK; k1++)
      for (k2 = 0; k2 < _PB_NM; k2++)
        sum += A[i][k1] * B[k1][k2] * C[k2][j];
    G[i][j] = sum;
  }
